import os
import json
import traceback

map_path = os.path.abspath(os.path.dirname(__file__) + '/io_map.json')


class IOTable(object):
    """
    IOTable     class to parse io config json file
    :param:     profile:     string, file path of the io configuration json file, default None
    :example:
                io_table = IOTable(pin_map, "/mix/hwio.json")
    """

    def __init__(self, profile=map_path):
        self._dictIOMap = {}
        self._dcrIOMap = {}
        if profile:
            assert os.path.exists(profile)
            with open(profile, 'r') as f:
                self._dictIOMap = json.load(f)

    def get_by_netname(self, net, sub_net=None, table='HWIO_Relay_Table'):
        """
        search every sub table(relay_table, measure_table, eeprom_table...) to get the config
        for input net
        :param: net,    string,    main net name,
        :param: sub_net string,    sub net name, can be None
        :param: table   string,    indicate to use which sub_table
        :example:
            config = getby_netname("PP_VCC_BATT", "CONNECT")
        """
        try:
            if sub_net:
                io = self._dictIOMap[table][net][sub_net]['IO']
            else:
                io = self._dictIOMap[net]['IO']
            return io
        except:
            # return False
            print(Exception("Invalid net {} -- {} in table {}".format(net, sub_net, table)))
            print(traceback.format_exc())
            return False


if __name__ == '__main__':
    ioTable = IOTable()
    print(ioTable.get_by_netname('FIXTURE_GND_TO_DUT_GND', 'CONNECT'))
